"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["483486"],{700896(e){e.exports=JSON.parse('{"tag":{"label":"buff","permalink":"/dst-api-webdocs/docs/tags/buff","allTagsPath":"/dst-api-webdocs/docs/tags","count":27,"items":[{"id":"game-scripts/prefabs/abigailforcefield","title":"Abigailforcefield","description":"Applies a forcefield effect to an entity, granting absorption and the forcefield tag, typically as a visual and gameplay feedback from Abigail\'s abilities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/abigailforcefield"},{"id":"game-scripts/widgets/avengingghostbadge","title":"Avengingghostbadge","description":"Displays a custom ghost buff indicator on the player\'s HUD with a dynamic symbol and timer.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/avengingghostbadge"},{"id":"game-scripts/components/battleborn","title":"Battleborn","description":"Manages the \\"Battleborn\\" mechanic\u2014accumulating a resource when attacking enemies and consuming it to heal, repair equipment, or restore sanity when a threshold is reached.","permalink":"/dst-api-webdocs/docs/game-scripts/components/battleborn"},{"id":"game-scripts/prefabs/battlesongdefs","title":"Battlesongdefs","description":"Defines configuration and behavior for Wathgrithr\'s battlesong buffs and instant-use battle quotes in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/battlesongdefs"},{"id":"game-scripts/prefabs/battlesongs","title":"Battlesongs","description":"Generates combat buff prefabs and their associated song definitions for the Battlesinger class, integrating with the singing inspiration system and debuff lifecycle.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/battlesongs"},{"id":"game-scripts/components/coach","title":"Coach","description":"Provides periodic support effects (sanity and fight buffs) to nearby players and followers when the host entity is tagged as \\"coaching\\".","permalink":"/dst-api-webdocs/docs/game-scripts/components/coach"},{"id":"game-scripts/prefabs/critterbuff_lunarmoth","title":"Critterbuff Lunarmoth","description":"Creates a temporary lighting FX entity that fades in/out and flickers to simulate a lunar moth\'s glow effect.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/critterbuff_lunarmoth"},{"id":"game-scripts/components/feasts","title":"Feasts","description":"Manages group coordination, buff application, and announcement logic for winter feast events when multiple players and tables interact.","permalink":"/dst-api-webdocs/docs/game-scripts/components/feasts"},{"id":"game-scripts/prefabs/foodbuffs","title":"Foodbuffs","description":"Factory for creating temporary food-based buff prefabs that apply one-time or extended status effects to target entities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/foodbuffs"},{"id":"game-scripts/prefabs/ghostvision_buff","title":"Ghostvision Buff","description":"Applies a networked night vision effect to players by manipulating lighting and colour correction, while managing buff lifetime and persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ghostvision_buff"},{"id":"game-scripts/prefabs/halloweenpotion_buffs","title":"Halloweenpotion Buffs","description":"Creates and manages buff entities that apply periodic health/sanity restoration or bravery effects when attached via the halloween potion items.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/halloweenpotion_buffs"},{"id":"game-scripts/prefabs/healthregenbuff","title":"Healthregenbuff","description":"A temporary entity that periodically restores health to a target using jellybean-style regen logic, stopping automatically if the target dies or becomes a ghost.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/healthregenbuff"},{"id":"game-scripts/prefabs/hermitcrabtea","title":"Hermitcrabtea","description":"Factory prefab generator for hermit crab tea items and their associated debuff effects, supporting reusable consumption, stat restoration, and temporary buffs.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermitcrabtea"},{"id":"game-scripts/prefabs/hermitcrabtea_defs","title":"Hermitcrabtea Defs","description":"Defines tea ingredients and their associated buffs for the Hermit Crab Teapot prefab.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermitcrabtea_defs"},{"id":"game-scripts/prefabs/hungerregenbuff","title":"Hungerregenbuff","description":"Applies a periodic hunger regeneration buff to a target entity, adjusting output based on eater and food memory multipliers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hungerregenbuff"},{"id":"game-scripts/prefabs/merm_healthregenbuff","title":"Merm Healthregenbuff","description":"Applies periodic health regeneration to a target entity for a fixed duration, used by merm characters and related gameplay elements.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/merm_healthregenbuff"},{"id":"game-scripts/prefabs/mermking_gear_buffs","title":"Mermking Gear Buffs","description":"Provides prefab factory functions to generate temporary debuff components for Merm King gear upgrades (Trident, Crown, Pauldron) that modify combat stats of attached targets.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mermking_gear_buffs"},{"id":"game-scripts/prefabs/nonslipgrit","title":"Nonslipgrit","description":"Applies a temporary non-slip buff to entities while consuming fuel over time, optionally spawning ice pools when boosted.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nonslipgrit"},{"id":"game-scripts/widgets/pethealthbadge","title":"Pethealthbadge","description":"Displays a pet\'s health as a badge with optional dual buff icons and directional health-change indicators.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/pethealthbadge"},{"id":"game-scripts/components/singinginspiration","title":"Singinginspiration","description":"Manages the battle song inspiration system for Wathgrithr, tracking inspiration points and active song buffs.","permalink":"/dst-api-webdocs/docs/game-scripts/components/singinginspiration"},{"id":"game-scripts/prefabs/spawnprotectionbuff","title":"Spawnprotectionbuff","description":"Applies and manages a temporary spawn protection buff that grants temporary invulnerability and collision exclusion to a target entity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spawnprotectionbuff"},{"id":"game-scripts/prefabs/spider_buffs","title":"Spider Buffs","description":"Creates temporary debuff prefabs applied to spiders to enforce behaviors like whistle immunity, bedazzlement, and summoning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spider_buffs"},{"id":"game-scripts/prefabs/spiderden_bedazzler","title":"Spiderden Bedazzler","description":"A single-use consumable item that applies a bedazzling buff to a target upon use, designed for spider-related gameplay interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spiderden_bedazzler"},{"id":"game-scripts/prefabs/trap_vines","title":"Trap Vines","description":"A deployable trap entity that detects moving targets within its radius, applies a movement speed debuff, and deals damage.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trap_vines"},{"id":"game-scripts/prefabs/wintersfeastbuff","title":"Wintersfeastbuff","description":"Applies a timed damage-healing buff that restores health, hunger, and sanity over time while reducing hunger burn rate, and supports bonus duration extension based on feast statistics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wintersfeastbuff"},{"id":"game-scripts/prefabs/wurt","title":"Wurt","description":"Implements the Wurt character\'s unique gameplay mechanics including pathfinding support, wetness-based skill interactions, and Merm King upgrades via debuff-based planar buffs for followers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wurt"},{"id":"game-scripts/prefabs/yoth_buffs","title":"Yoth Buffs","description":"Applies a timed buff to a target entity, automatically removing itself when the timer expires or the target dies.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yoth_buffs"}],"unlisted":false}}')}}]);